"use client";

import { useEffect, useState, useRef, useMemo } from "react";
import { motion, useScroll, useSpring, AnimatePresence } from "framer-motion";
import TimelineCard from "./TimelineCard";
import EraSelector from "./EraSelector";
import { ChevronLeft, ChevronRight, Home, LayoutGrid } from "lucide-react";
import TimeScale from "./TimeScale";

interface BiblicalEvent {
  id: string;
  title: string;
  description: string;
  verse: string;
  date: string;
  year: number;
  category: string;
  era: string;
  eraDescription: string;
}

interface Era {
  name: string;
  description: string;
  firstEventId: string;
  periods: { name: string; firstEventId: string }[];
}

type ViewMode = "eras" | "timeline";

export default function TimelineContainer() {
  const [events, setEvents] = useState<BiblicalEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState<ViewMode>("eras");
  const [activeEra, setActiveEra] = useState<string>("");
  const [currentYear, setCurrentYear] = useState<number>(0);
  const [scrollPercent, setScrollPercent] = useState<number>(0);

  const containerRef = useRef<HTMLDivElement>(null);
  
  const { scrollXProgress } = useScroll({ container: containerRef });
  const scaleX = useSpring(scrollXProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001
  });

  // Calculate Eras and Periods from events
  const eras = useMemo(() => {
    const eraMap = new Map<string, Era>();
    const sorted = [...events].sort((a, b) => a.year - b.year);
    
    sorted.forEach((event) => {
      if (!eraMap.has(event.era)) {
        eraMap.set(event.era, {
          name: event.era,
          description: event.eraDescription,
          firstEventId: event.id,
          periods: []
        });
      }
      
      const era = eraMap.get(event.era)!;
      if (!era.periods.some(p => p.name === event.category)) {
        era.periods.push({
          name: event.category,
          firstEventId: event.id
        });
      }
    });
    return Array.from(eraMap.values());
  }, [events]);

  useEffect(() => {
    async function fetchEvents() {
      try {
        const res = await fetch("/api/events");
        const data = await res.json();
        const sortedData = data.sort((a: BiblicalEvent, b: BiblicalEvent) => a.year - b.year);
        setEvents(sortedData);
      } catch (error) {
        console.error("Failed to fetch events", error);
      } finally {
        setLoading(false);
      }
    }
    fetchEvents();
  }, []);

  // Update active era on scroll
  useEffect(() => {
    if (viewMode !== "timeline") return;
    
    const container = containerRef.current;
    if (!container) return;

    const handleScroll = () => {
      const { scrollLeft, scrollWidth, offsetWidth } = container;
      const progress = scrollLeft / (scrollWidth - offsetWidth);
      setScrollPercent(progress);

      // Encontrar evento más cercano
      const index = Math.round(scrollLeft / (offsetWidth * 0.8));
      if (events[index]) {
        setActiveEra(events[index].era);
        setCurrentYear(events[index].year);
      }
    };

    container.addEventListener("scroll", handleScroll, { passive: true });
    return () => container.removeEventListener("scroll", handleScroll);
  }, [events, viewMode]);

  const handleSelectEra = (eventId: string) => {
    setViewMode("timeline");
    
    const checkAndScroll = () => {
      const element = document.getElementById(`event-${eventId}`);
      if (element && containerRef.current) {
        element.scrollIntoView({
          behavior: "auto",
          inline: "center",
          block: "nearest"
        });
        return true;
      }
      return false;
    };

    let attempts = 0;
    const interval = setInterval(() => {
      attempts++;
      if (checkAndScroll() || attempts > 20) {
        clearInterval(interval);
      }
    }, 30);
  };

  const scroll = (direction: "left" | "right") => {
    if (containerRef.current) {
      const scrollAmount = window.innerWidth * 0.6;
      containerRef.current.scrollBy({
        left: direction === "left" ? -scrollAmount : scrollAmount,
        behavior: "smooth"
      });
    }
  };

  if (loading) {
    return (
      <div className="flex-1 flex items-center justify-center bg-canvas h-screen">
        <motion.div 
          animate={{ rotate: 360 }}
          transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
          className="w-16 h-16 border-4 border-black border-t-intent-action"
        />
      </div>
    );
  }

  return (
    <div className="relative flex-1 flex flex-col bg-canvas overflow-hidden min-h-screen">
      {/* Navigation Bar */}
      <nav className="fixed top-0 left-0 right-0 z-50 p-4 md:p-6 flex justify-between items-center bg-canvas/80 backdrop-blur-sm border-b-structure border-black">
        <div className="flex gap-2 md:gap-4">
          <Link href="/" className="btn-secondary flex items-center gap-2 bg-white text-xs md:text-base">
            <Home className="w-4 h-4 md:w-5 h-5" />
            <span className="hidden sm:inline">INICIO</span>
          </Link>
          {viewMode === "timeline" && (
            <button 
              onClick={() => setViewMode("eras")}
              className="btn-secondary flex items-center gap-2 bg-white text-xs md:text-base"
            >
              <LayoutGrid className="w-4 h-4 md:w-5 h-5" />
              <span className="hidden sm:inline">CAMBIAR ERA</span>
            </button>
          )}
        </div>

        {viewMode === "timeline" && (
          <div className="flex gap-2 md:gap-4">
            <button 
              onClick={() => scroll("left")}
              className="btn-secondary bg-white p-2"
              aria-label="Desplazar a la izquierda"
            >
              <ChevronLeft className="w-5 h-5 md:w-6 h-6" />
            </button>
            <button 
              onClick={() => scroll("right")}
              className="btn-secondary bg-white p-2"
              aria-label="Desplazar a la derecha"
            >
              <ChevronRight className="w-5 h-5 md:w-6 h-6" />
            </button>
          </div>
        )}
      </nav>

      <AnimatePresence mode="wait">
        {viewMode === "eras" ? (
          <motion.div
            key="eras-view"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="flex-1 flex flex-col pt-24 md:pt-32"
          >
            <EraSelector eras={eras} onSelectEra={handleSelectEra} />
          </motion.div>
        ) : (
          <motion.div
            key="timeline-view"
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 1.02 }}
            className="flex-1 flex flex-col pt-24 md:pt-32"
          >
            {/* Timeline Scrollable Area */}
            <div 
              ref={containerRef}
              className="flex-1 overflow-x-auto overflow-y-hidden snap-x snap-mandatory flex items-center gap-[5vw] px-[10vw] no-scrollbar pb-24"
            >
              {events.map((event, index) => (
                <div 
                  key={event.id} 
                  id={`event-${event.id}`}
                  className="snap-center"
                >
                  <TimelineCard event={event} index={index} />
                </div>
              ))}
            </div>

            {/* Progress Bar */}
            <motion.div 
              className="fixed bottom-0 left-0 right-0 h-3 md:h-4 bg-intent-action z-40 origin-left border-t-structure border-black"
              style={{ scaleX }}
            />

            {/* Background Text Decor */}
            <div className="fixed top-1/2 left-0 right-0 -z-10 opacity-[0.02] md:opacity-[0.03] select-none pointer-events-none -translate-y-1/2 overflow-hidden">
              <h2 className="text-[25vw] md:text-[30vw] leading-none font-black text-black whitespace-nowrap text-center">
                {activeEra.split(' ')[2] || 'HISTORIA'}
              </h2>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
